function Expand-NvidiaDriverPackage([Parameter(Mandatory)]$DriverPackage, [ValidateSet("Launch","Install","Open",$null)][string]$Post, [switch]$All, [array]$Components = @()) {
    $DriverPackage = Resolve-Path $DriverPackage
    $Output = ($DriverPackage -split "$((Get-Item $DriverPackage).Extension)", 2, 'SimpleMatch')[0]
    $7Zip, $PostCfg, $PresentationsCfg = "$env:TEMP\7zr.exe", "$Output\setup.cfg", "$Output/NVI2/presentations.cfg"
    $ComponentsFolders = "Display.Driver NVI2 EULA.txt ListDevices.txt setup.cfg setup.exe"
    if ($All) { $ComponentsFolders = "" }
    elseif ($Components) {
        foreach ($c in $Components) {
            if ($c -notin "PhysX", "HDAudio") { Write-Error "Invalid Component: $c" -ErrorAction Stop }
            $ComponentsFolders += " $c"
        }
    }

    Write-Host "Extracting `"$DriverPackage`" -> `"$Output`""; Remove-Item $Output -Recurse -Force -ErrorAction SilentlyContinue
    (New-Object Net.WebClient).DownloadFile("https://www.7-zip.org/a/7zr.exe", $7Zip)
    & $7Zip x -bso0 -bsp1 -bse1 -aoa $DriverPackage @($ComponentsFolders -split ' ' | Where-Object { $_ }) -o"$Output"
    $EulaTags = '<file name="${{EulaHtmlFile}}"/>', '<file name="${{FunctionalConsentFile}}"/>', '<file name="${{PrivacyPolicyFile}}"/>'
    (Get-Content $PostCfg -Encoding Ascii) | ForEach-Object { $_.Trim() -in $EulaTags ? "" : $_ } | Set-Content $PostCfg -Encoding Ascii

    $ProgressKeys = "ProgressPresentationUrl", "ProgressPresentationSelectedPackageUrl"
    (Get-Content $PresentationsCfg -Encoding Ascii) | ForEach-Object {
        $line = $_
        foreach ($key in $ProgressKeys) { if ($line -like "`t`t<string name=`"$key`" value=*") { $line = "`t`t<string name=`"$key`" value=`"`"/>" } }
        $line
    } | Set-Content $PresentationsCfg -Encoding Ascii
    Write-Host "Extracted: $DriverPackage"
}

function Get-WithAria2c($Url, $OutFile) {
    $aria = (Get-Command aria2c.exe -ErrorAction SilentlyContinue).Source
    if (-not $aria) { return $false }
    $aArgs = "--console-log-level=error", "--file-allocation=none", "--dir=$(Split-Path $OutFile)", "--out=$(Split-Path $OutFile -Leaf)",
             "--max-connection-per-server=16", "--split=16", "--retry-wait=5", "--max-tries=5", $Url
    (Start-Process $aria -ArgumentList $aArgs -NoNewWindow -Wait -PassThru).ExitCode -eq 0
}

$Downloads = (New-Object -ComObject Shell.Application).Namespace('shell:Downloads').Self.Path
Write-Host "Detecting NVIDIA GPU and driver..."
$VideoController = Get-CimInstance Win32_VideoController | Where-Object Name -match "NVIDIA" | Select-Object -First 1
if (-not $VideoController) { Write-Error "No NVIDIA GPU detected. Exiting."; exit 1 }
$GpuName = $VideoController.Name -replace '^NVIDIA\s+'; Write-Host "Detected GPU:`t`t$($VideoController.Name)"
$ins_version = try { ($VideoController.DriverVersion.Replace('.', '')[-5..-1] -join '').Insert(3, '.') } catch { Write-Host -ForegroundColor Yellow "Unable to determine installed driver version."; $null }
if ($ins_version) { Write-Host "Installed version:`t$ins_version" }
if (-not $GpuDatabase.ContainsKey($GpuName)) { Write-Error "'$GpuName' isn't in the built-in GPU database. Covers desktop GeForce GTX 400 through RTX 50 series. Look up psid/pfid at https://www.nvidia.com/Download/API/lookupValueSearch.aspx?TypeID=3 and add it to `$GpuDatabase."; exit 1 }
$psid, $pfid = $GpuDatabase[$GpuName].psid, $GpuDatabase[$GpuName].pfid
$uri = "https://gfwsl.geforce.com/services_toolkit/services/com/nvidia/services/AjaxDriverService.php?func=DriverManualLookup&psid=$psid&pfid=$pfid&osID=57&languageCode=1033&isWHQL=1&dch=1&sort1=0&numberOfResults=1"
try { $latestVersion = ((Invoke-WebRequest $uri).Content | ConvertFrom-Json).IDS[0].downloadInfo.Version; Write-Host "Latest version:`t`t$latestVersion" } catch { Write-Error "Failed to get latest NVIDIA driver version."; exit }
if ($ins_version -eq $latestVersion) { Write-Host "Already up to date. Exiting in 5s..."; Start-Sleep 5; exit }
$dlPath = Join-Path $Downloads "$latestVersion-NVIDIA.exe"
$downloadUrl = "https://international.download.nvidia.com/Windows/$latestVersion/$latestVersion-desktop-win10-win11-64bit-international-dch-whql.exe"
Write-Host "Downloading latest NVIDIA driver to:`n$dlPath"
$ok = Get-WithAria2c $downloadUrl $dlPath
if (-not $ok) { Write-Host "aria2c unavailable or failed. Falling back to Invoke-WebRequest..." try { Invoke-WebRequest $downloadUrl -OutFile $dlPath -ErrorAction Stop; $ok = $true } catch { Write-Host "Download failed. Trying fallback RP build..."; $ok = Get-WithAria2c ($downloadUrl -replace '\.exe$', '-rp.exe') $dlPath } }
if (-not $ok) { Write-Error "Download failed. Exiting."; exit 1 }
$unpackedFolder = Join-Path $Downloads ([System.IO.Path]::GetFileNameWithoutExtension($dlPath))
Expand-NvidiaDriverPackage $dlPath
Write-Host "Installing $dlPath..."; Start-Process "$unpackedFolder\setup.exe" -ArgumentList "-passive -noeula -disable-nvtelemetry" -Wait
Write-Host "Cleaning up..."; Remove-Item $dlPath, $unpackedFolder -Force -Recurse
Write-Host "All done. Exiting in 5s..."; Start-Sleep 5